    if(tokens.empty()||tokens[0]=="null")return nullptr;
    TreeNode* root=new TreeNode(stoi(tokens[0]));
    queue<TreeNode*> q;q.push(root);int i=1;
    while(i<(int)tokens.size()){TreeNode* node=q.front();q.pop();
    if(i<(int)tokens.size()&&tokens[i]!="null"){node->left=new TreeNode(stoi(tokens[i]));q.push(node->left);}i++;
    if(i<(int)tokens.size()&&tokens[i]!="null"){node->right=new TreeNode(stoi(tokens[i]));q.push(node->right);}i++;}
